DROP TABLE IF EXISTS "public"."attendances";
-- This script only contains the table creation statements and does not fully represent the table in the database. Do not use it as a backup.

-- Sequence and defined type
CREATE SEQUENCE IF NOT EXISTS attendances_id_seq;

-- Table Definition
CREATE TABLE "public"."attendances" (
    "id" int8 NOT NULL DEFAULT nextval('attendances_id_seq'::regclass),
    "branch_id" int8 NOT NULL,
    "employee_id" int8 NOT NULL,
    "start_time" timestamptz NOT NULL,
    "end_time" timestamptz,
    "type" varchar(255) NOT NULL,
    "status" varchar(255) NOT NULL DEFAULT 'reject'::character varying,
    "reason_manual_addition" varchar(255),
    "manager_comment" text,
    "created_at" timestamp(0),
    "updated_at" timestamp(0),
    CONSTRAINT "attendances_branch_id_foreign" FOREIGN KEY ("branch_id") REFERENCES "public"."branches"("id") ON DELETE CASCADE,
    CONSTRAINT "attendances_employee_id_foreign" FOREIGN KEY ("employee_id") REFERENCES "public"."employees"("id") ON DELETE CASCADE,
    PRIMARY KEY ("id")
);

